1444 |     async fn enforce_context_window(
1445 |         &mut self,
1446 |         provider: Arc<dyn crate::provider::Provider>,
1447 |         model: &str,
1448 |         system_prompt: &str,
1449 |         tools: &[ToolDefinition],
1450 |     ) -> Result<()> {
