1452 | 
1453 |         // Reserve response tokens + a small fixed overhead for tool schemas,
1454 |         // protocol framing, and provider-specific wrappers.
1455 |         let reserve = session_completion_max_tokens().saturating_add(2048);
1456 |         let budget = ctx_window.saturating_sub(reserve);
1457 |         let safety_budget = (budget as f64 * 0.90) as usize;
1458 | 
1459 |         // Try progressively more aggressive compression.
1460 |         let keep_last_candidates = [16usize, 12, 8, 6];
1461 |         for keep_last in keep_last_candidates {
1462 |             let est = estimate_request_tokens(system_prompt, &self.messages, tools);
1463 |             if est <= safety_budget {
1464 |                 return Ok(());
1465 |             }
1466 | 
1467 |             tracing::info!(
1468 |                 est_tokens = est,
1469 |                 ctx_window,
1470 |                 safety_budget,
1471 |                 keep_last,
1472 |                 "Context window approaching limit; compressing older session history"
1473 |             );
1474 | 
1475 |             let did = self
1476 |                 .compress_history_keep_last(
